package com.raonmate.backend.budget.domain;
import com.raonmate.backend.workshop.domain.Workshop; import jakarta.persistence.*; import java.math.BigDecimal; import java.time.Instant; import java.util.*;
@Entity @Table(name="budget_plans") public class BudgetPlan {@Id private UUID id; @OneToOne(fetch=FetchType.LAZY,optional=false) @JoinColumn(name="workshop_id",unique=true,nullable=false) private Workshop workshop; @ElementCollection @CollectionTable(name="budget_items",joinColumns=@JoinColumn(name="budget_id")) @OrderColumn(name="item_order") private List<Item> items=new ArrayList<>(); @Column(nullable=false) private Instant updatedAt; protected BudgetPlan(){} public BudgetPlan(Workshop w){id=UUID.randomUUID();workshop=w;updatedAt=Instant.now();} public void replace(List<Item> v){items.clear();items.addAll(v);updatedAt=Instant.now();} public UUID getId(){return id;} public Workshop getWorkshop(){return workshop;} public List<Item> getItems(){return List.copyOf(items);} public Instant getUpdatedAt(){return updatedAt;}
@Embeddable public static class Item {@Column(nullable=false,length=50) private String category;@Column(nullable=false,length=150) private String name;@Column(nullable=false,precision=15,scale=0) private BigDecimal amount;@Column(length=500) private String note;protected Item(){} public Item(String c,String n,BigDecimal a,String x){category=c;name=n;amount=a;note=x;}public String getCategory(){return category;}public String getName(){return name;}public BigDecimal getAmount(){return amount;}public String getNote(){return note;}}}
